    p7_connection->previous_t1 = vnf_get_current_time_hr();
  }

  int retval = p7_config->send_p7_msg((vnf_p7_t *)p7_config, &tx_data_req->header);
  if (retval != 0) {
    LOG_E(PHY, "%s() Problem sending retval:%d\n", __FUNCTION__, retval);
  } else {
    // Stop timer and calculate latency on successful transmission
    if (p7_connection) {
      p7_connection->previous_t2 = vnf_get_current_time_hr();

      // Calculate latency in microseconds
      uint32_t latency_us = TIMEHR_USEC(p7_connection->previous_t2) - TIMEHR_USEC(p7_connection->previous_t1);
      if (TIMEHR_USEC(p7_connection->previous_t2) < TIMEHR_USEC(p7_connection->previous_t1)) {
        // Handle wraparound
        latency_us += 1000000;
      }

      // Store latency in circular buffer indexed by sequence_number
      uint8_t index = p7_connection->sequence_number % 8;
      p7_connection->latency[index] = latency_us;

      // Update running average using weighted formula: (average * 7 + new_sample) / 8
      if (p7_connection->average_latency == 0) {
        // First sample
        p7_connection->average_latency = latency_us;
      } else {
        p7_connection->average_latency = (p7_connection->average_latency * 7 + latency_us) / 8;
      }

      // Increment sequence number for next request
      p7_connection->sequence_number++;
    }

    tx_data_req->Number_of_PDUs = 0;
  }

  return retval;
}
